import{_ as a,c as o,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Permissões e Mecanismos de Segurança: Matriz de Limites de Capacidade, Proteção contra Acesso Não Autorizado, Configuração de Permissões do Claude Code e Melhores Práticas de Segurança | AI App Factory","description":"Aprenda sobre a Matriz de Limites de Capacidade do AI App Factory, mecanismos de verificação de permissões e estratégias de proteção contra acesso não autorizado. Domine como configurar permissões do Claude Code, prevenir operações não autorizadas de Agentes, lidar com exceções de segurança e garantir a execução segura e estável do pipeline. Este tutorial inclui explicação detalhada dos três mecanismos de proteção, exercícios práticos de configuração de permissões, fluxo completo de tratamento de acesso não autorizado, validação de habilidades obrigatórias e guia de melhores práticas de segurança.","frontmatter":{"title":"Permissões e Mecanismos de Segurança: Matriz de Limites de Capacidade, Proteção contra Acesso Não Autorizado, Configuração de Permissões do Claude Code e Melhores Práticas de Segurança | AI App Factory","sidebarTitle":"Permissões e Segurança","subtitle":"Permissões e Mecanismos de Segurança: Matriz de Limites de Capacidade e Proteção contra Acesso Não Autorizado","description":"Aprenda sobre a Matriz de Limites de Capacidade do AI App Factory, mecanismos de verificação de permissões e estratégias de proteção contra acesso não autorizado. Domine como configurar permissões do Claude Code, prevenir operações não autorizadas de Agentes, lidar com exceções de segurança e garantir a execução segura e estável do pipeline. Este tutorial inclui explicação detalhada dos três mecanismos de proteção, exercícios práticos de configuração de permissões, fluxo completo de tratamento de acesso não autorizado, validação de habilidades obrigatórias e guia de melhores práticas de segurança.","tags":["Avançado","Segurança","Controle de Permissões","Matriz de Limites de Capacidade","Claude Code"],"prerequisite":["advanced-orchestrator"],"order":170},"headers":[],"relativePath":"pt/hyz1992/agent-app-factory/advanced/security-permissions/index.md","filePath":"pt/hyz1992/agent-app-factory/advanced/security-permissions/index.md"}'),d={name:"pt/hyz1992/agent-app-factory/advanced/security-permissions/index.md"};function t(r,e,n,c,l,p){return s(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="permissoes-e-mecanismos-de-seguranca-matriz-de-limites-de-capacidade-e-protecao-contra-acesso-nao-autorizado" tabindex="-1">Permissões e Mecanismos de Segurança: Matriz de Limites de Capacidade e Proteção contra Acesso Não Autorizado <a class="header-anchor" href="#permissoes-e-mecanismos-de-seguranca-matriz-de-limites-de-capacidade-e-protecao-contra-acesso-nao-autorizado" aria-label="Permalink to &quot;Permissões e Mecanismos de Segurança: Matriz de Limites de Capacidade e Proteção contra Acesso Não Autorizado&quot;">​</a></h1><h2 id="o-que-voce-podera-fazer-apos-este-curso" tabindex="-1">O que Você Poderá Fazer Após Este Curso <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-este-curso" aria-label="Permalink to &quot;O que Você Poderá Fazer Após Este Curso&quot;">​</a></h2><ul><li>Compreender o princípio de design da Matriz de Limites de Capacidade e o mecanismo de isolamento de permissões</li><li>Aprender a configurar o arquivo de permissões do Claude Code, evitando o uso de <code>--dangerously-skip-permissions</code></li><li>Dominar o fluxo de tratamento de operações não autorizadas e métodos de recuperação</li><li>Entender o mecanismo de validação de uso de habilidades obrigatórias</li><li>Ser capaz de identificar e corrigir problemas de segurança relacionados a permissões</li></ul><h2 id="sua-situacao-atual" tabindex="-1">Sua Situação Atual <a class="header-anchor" href="#sua-situacao-atual" aria-label="Permalink to &quot;Sua Situação Atual&quot;">​</a></h2><p>Você pode ter encontrado estas situações:</p><ul><li>Não saber por que o Agente não consegue acessar determinados arquivos</li><li>Ao executar <code>factory run</code>, sempre ser solicitado a conceder permissões, usando diretamente <code>--dangerously-skip-permissions</code> para ignorar</li><li>Não estar claro sobre os limites de permissão entre Agentes, preocupado que operações não autorizadas causem contaminação de dados</li><li>Não saber como lidar e recuperar após ocorrência de acesso não autorizado</li></ul><p>Se esses problemas o incomodam, este capítulo ajudará você a estabelecer um conhecimento completo sobre permissões e segurança.</p><h2 id="quando-usar-esta-tecnica" tabindex="-1">Quando Usar Esta Técnica <a class="header-anchor" href="#quando-usar-esta-tecnica" aria-label="Permalink to &quot;Quando Usar Esta Técnica&quot;">​</a></h2><p>Quando você precisar:</p><ul><li><strong>Configurar o Claude Code</strong>: Definir o arquivo de permissões correto para projetos Factory</li><li><strong>Depurar problemas de permissão</strong>: Investigar por que um Agente não consegue ler ou escrever arquivos específicos</li><li><strong>Tratar exceções de acesso não autorizado</strong>: Recuperar pipelines interrompidos causados por operações não autorizadas</li><li><strong>Expandir Agentes</strong>: Ao adicionar novos Agentes, definir seus limites de permissão</li><li><strong>Auditoria de segurança</strong>: Verificar se a configuração de permissões do projeto existente é razoável</li></ul><h2 id="ideia-central" tabindex="-1">Ideia Central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia Central&quot;">​</a></h2><p>O mecanismo de segurança do AI App Factory é baseado na <strong>Matriz de Limites de Capacidade</strong> (Capability Boundary Matrix), garantindo que cada Agente opere apenas em diretórios autorizados.</p><p><strong>Lembre-se desta analogia</strong>:</p><ul><li>Os Agentes são como <strong>trabalhadores especializados</strong> em uma fábrica</li><li>A Matriz de Limites de Capacidade é como uma <strong>licença de trabalho</strong>, especificando claramente quais oficinas cada trabalhador pode entrar e quais equipamentos pode operar</li><li>O orquestrador Sisyphus é como um <strong>supervisor de segurança</strong>, verificando as licenças quando os trabalhadores entram ou saem das oficinas, garantindo que não haja comportamentos não autorizados</li></ul><p><strong>Mecanismo de Três Camadas de Proteção</strong>:</p><table tabindex="0"><thead><tr><th>Nível</th><th>Responsabilidade</th><th>Momento da Verificação</th></tr></thead><tbody><tr><td><strong>Permissões do Claude Code</strong></td><td>Permissões de leitura e escrita no sistema de arquivos</td><td>Quando o assistente de IA é iniciado</td></tr><tr><td><strong>Matriz de Limites de Capacidade</strong></td><td>Permissões de acesso a diretórios do Agente</td><td>Antes e depois da execução da fase</td></tr><tr><td><strong>Validação de Habilidades Obrigatórias</strong></td><td>Requisitos de uso de habilidades específicas em determinadas fases</td><td>Nas fases bootstrap e ui</td></tr></tbody></table><h2 id="detalhes-da-matriz-de-limites-de-capacidade" tabindex="-1">Detalhes da Matriz de Limites de Capacidade <a class="header-anchor" href="#detalhes-da-matriz-de-limites-de-capacidade" aria-label="Permalink to &quot;Detalhes da Matriz de Limites de Capacidade&quot;">​</a></h2><h3 id="por-que-e-necessario-isolamento-de-permissoes" tabindex="-1">Por Que É Necessário Isolamento de Permissões? <a class="header-anchor" href="#por-que-e-necessario-isolamento-de-permissoes" aria-label="Permalink to &quot;Por Que É Necessário Isolamento de Permissões?&quot;">​</a></h3><p>Imagine o que aconteceria sem limites de permissão:</p><ul><li><strong>Agente PRD modifica arquivos de UI</strong>: O design da UI é alterado de forma desordenada, sem possibilidade de rastreamento</li><li><strong>Agente Tech lê arquivos de Code</strong>: A arquitetura técnica é influenciada pela implementação do código, desviando-se do princípio MVP</li><li><strong>Agente Code modifica o PRD</strong>: O documento de requisitos é &quot;contaminado&quot; pela lógica do código, causando confusão de responsabilidades</li></ul><p><strong>Resposta</strong>: Limites de responsabilidade não claros, produtos sem rastreabilidade, qualidade sem garantia.</p><p>A Matriz de Limites de Capacidade garante a separação de responsabilidades ao restringir as permissões de leitura e escrita de cada Agente.</p><h3 id="tabela-da-matriz-de-permissoes" tabindex="-1">Tabela da Matriz de Permissões <a class="header-anchor" href="#tabela-da-matriz-de-permissoes" aria-label="Permalink to &quot;Tabela da Matriz de Permissões&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agente</th><th>Diretórios Legíveis</th><th>Diretórios Graváveis</th><th>Descrição</th></tr></thead><tbody><tr><td><strong>bootstrap</strong></td><td>Nenhum</td><td><code>input/</code></td><td>Cria ou modifica <code>idea.md</code> apenas no diretório <code>input/</code></td></tr><tr><td><strong>prd</strong></td><td><code>input/</code></td><td><code>artifacts/prd/</code></td><td>Lê arquivo de ideias, gera PRD; proibido escrever em outros diretórios</td></tr><tr><td><strong>ui</strong></td><td><code>artifacts/prd/</code></td><td><code>artifacts/ui/</code></td><td>Lê PRD, gera UI Schema e preview</td></tr><tr><td><strong>tech</strong></td><td><code>artifacts/prd/</code></td><td><code>artifacts/tech/</code>, <code>artifacts/backend/prisma/</code></td><td>Lê PRD, gera design técnico e modelos de dados</td></tr><tr><td><strong>code</strong></td><td><code>artifacts/ui/</code>, <code>artifacts/tech/</code>, <code>artifacts/backend/prisma/</code></td><td><code>artifacts/backend/</code>, <code>artifacts/client/</code></td><td>Gera código backend e cliente com base na UI e design técnico; não pode modificar produtos upstream</td></tr><tr><td><strong>validation</strong></td><td><code>artifacts/backend/</code>, <code>artifacts/client/</code></td><td><code>artifacts/validation/</code></td><td>Valida qualidade do código, gera relatório de validação; somente leitura, não modifica código</td></tr><tr><td><strong>preview</strong></td><td><code>artifacts/backend/</code>, <code>artifacts/client/</code></td><td><code>artifacts/preview/</code></td><td>Lê serviços e clientes gerados, escreve instruções de demonstração</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Princípio Central</p><ul><li><strong>Dependência Unidirecional</strong>: Agente só pode ler produtos de fases upstream, não pode ler produtos de fases downstream ou do mesmo nível</li><li><strong>Responsabilidade Independente</strong>: Cada Agente só pode escrever em seu próprio diretório de saída</li><li><strong>Proibição de Acesso Não Autorizado</strong>: Operações de leitura e escrita não autorizadas são consideradas violações de segurança</li></ul></div><h3 id="fluxo-de-verificacao-de-permissoes" tabindex="-1">Fluxo de Verificação de Permissões <a class="header-anchor" href="#fluxo-de-verificacao-de-permissoes" aria-label="Permalink to &quot;Fluxo de Verificação de Permissões&quot;">​</a></h3><p>O orquestrador Sisyphus realiza verificações de permissão antes e depois da execução de cada fase:</p><p><strong>Antes da Execução (Informar Permissões)</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Sisyphus lê capability.matrix.md</span></span>
<span class="line"><span>2. Passa os diretórios legíveis e graváveis do Agente atual para o assistente de IA</span></span>
<span class="line"><span>3. O assistente de IA deve obedecer a essas restrições durante a execução</span></span></code></pre></div><p><strong>Depois da Execução (Validar Saída)</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Sisyphus escaneia arquivos criados ou modificados</span></span>
<span class="line"><span>2. Verifica se o caminho do arquivo está dentro do intervalo de diretórios autorizados do Agente</span></span>
<span class="line"><span>3. Se acesso não autorizado for detectado, trata imediatamente (veja mecanismo de tratamento de acesso não autorizado)</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Automação vs Manual</p><p>A verificação de permissões é realizada principalmente de forma automática pelo sistema de permissões do assistente de IA (Claude Code) e pela lógica de validação do Sisyphus. Intervenção manual só é necessária em casos anormais como acesso não autorizado.</p></div>`,32)])])}const g=a(d,[["render",t]]);export{m as __pageData,g as default};
